// Helper events and types for CacheNode <-> StorageProxy communication and proxy scheduling
event eProxyReadReq: (from: machine, key: int, opId: int, podId: int);
event eProxyWriteReq: (from: machine, key: int, value: int, opId: int, podId: int);
event eProxyTick;

type tProxyReq = (isWrite: bool, key: int, value: int, from: machine, podId: int, opId: int);

machine StorageProxy {
    var db: machine;

    // queue of storage-facing request ids
    var pendingQ: seq[int];
    // details for each queued/forwarded request
    var reqs: map[int, tProxyReq];
    // map of key -> reqId that has been forwarded and is awaiting storage response
    var inFlightByKey: map[int, int];
    var nextReqId: int;

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            pendingQ = default(seq[int]);
            reqs = default(map[int, tProxyReq]);
            inFlightByKey = default(map[int, int]);
            nextReqId = 1;
            goto Ready;
        }
    }

    state Ready {
        // Receive logical read from a cache node; enqueue a storage-facing read
        on eProxyReadReq do (r: (from: machine, key: int, opId: int, podId: int)) {
            var rid: int;
            var entry: tProxyReq;
            var pen: int;

            rid = nextReqId;
            nextReqId = nextReqId + 1;

            entry = (isWrite = false, key = r.key, value = 0, from = r.from, podId = r.podId, opId = r.opId);
            reqs[rid] = entry;

            // enqueue
            pendingQ += (sizeof(pendingQ), rid);
            pen = sizeof(pendingQ);

            // announce enqueue
            send this, eMonitorProxyEnqueue, (key = entry.key, podId = entry.podId, isWrite = false, pending = pen);

            // schedule a proxy step
            send this, eProxyTick;
        }

        // Receive logical write from a cache node; enqueue a storage-facing write
        on eProxyWriteReq do (w: (from: machine, key: int, value: int, opId: int, podId: int)) {
            var rid: int;
            var entry: tProxyReq;
            var pen: int;

            rid = nextReqId;
            nextReqId = nextReqId + 1;

            entry = (isWrite = true, key = w.key, value = w.value, from = w.from, podId = w.podId, opId = w.opId);
            reqs[rid] = entry;

            // enqueue
            pendingQ += (sizeof(pendingQ), rid);
            pen = sizeof(pendingQ);

            // announce enqueue
            send this, eMonitorProxyEnqueue, (key = entry.key, podId = entry.podId, isWrite = true, pending = pen);

            // schedule a proxy step
            send this, eProxyTick;
        }

        // Model network/proxy step: either hold queued requests or forward one to storage
        on eProxyTick do {
            StepQueue();
        }

        // Storage responses return to the proxy (caller = this). Deliver logical responses to cache nodes.
        on eStorageReadResp do (resp: (key: int, value: int)) {
            var key: int;
            var rid: int;
            var entry: tProxyReq;

            key = resp.key;
            assert key in inFlightByKey, format("Proxy received read resp for key {0} but no in-flight request!", key);
            rid = inFlightByKey[key];
            entry = reqs[rid];

            // clear in-flight for this key
            inFlightByKey -= (key);
            // drop req record
            reqs -= (rid);

            // announce delivered response back to cache node
            send this, eMonitorProxyResponseDelivered, (key = key, podId = entry.podId, isWrite = false);

            // deliver to the requesting cache node (fromCache = false; storage was touched)
            send entry.from, eReadResp, (key = key, value = resp.value, fromCache = false);

            // schedule next proxy step
            if (sizeof(pendingQ) > 0) {
                send this, eProxyTick;
            }
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var key: int;
            var rid: int;
            var entry: tProxyReq;

            key = resp.key;
            assert key in inFlightByKey, format("Proxy received write resp for key {0} but no in-flight request!", key);
            rid = inFlightByKey[key];
            entry = reqs[rid];

            // clear in-flight and request record
            inFlightByKey -= (key);
            reqs -= (rid);

            // announce delivered response back to cache node
            send this, eMonitorProxyResponseDelivered, (key = key, podId = entry.podId, isWrite = true);

            // deliver to the requesting cache node
            send entry.from, eWriteResp, (key = key, success = resp.success);

            // schedule next proxy step
            if (sizeof(pendingQ) > 0) {
                send this, eProxyTick;
            }
        }
    }

    fun StepQueue() {
        var n: int;
        var coin: int;
        var idx: int;
        var rid: int;
        var ent: tProxyReq;
        var newQ: seq[int];
        var j: int;

        n = sizeof(pendingQ);
        if (n == 0) {
            return;
        }

        // nondeterministically hold or forward
        coin = choose(2);
        if (coin == 0) {
            // hold all queued requests this step
            send this, eMonitorProxyHold, (pending = n);
            // maybe schedule another tick
            if (choose(2) == 1) {
                send this, eProxyTick;
            }
            return;
        }

        // choose any queued request
        idx = choose(n);
        rid = pendingQ[idx];
        ent = reqs[rid];

        // serialize per-key: if a request for this key is already in-flight, hold
        if (ent.key in inFlightByKey) {
            send this, eMonitorProxyHold, (pending = n);
            if (choose(2) == 1) {
                send this, eProxyTick;
            }
            return;
        }

        // forward to storage
        send this, eMonitorProxyForward, (key = ent.key, podId = ent.podId, isWrite = ent.isWrite, pending = n);

        if (ent.isWrite) {
            send db, eStorageWrite, (caller = this, key = ent.key, value = ent.value, podId = ent.podId);
        } else {
            send db, eStorageRead, (caller = this, key = ent.key, podId = ent.podId);
        }

        // dequeue the forwarded request
        newQ = default(seq[int]);
        j = 0;
        while (j < n) {
            if (j != idx) {
                newQ += (sizeof(newQ), pendingQ[j]);
            }
            j = j + 1;
        }
        pendingQ = newQ;

        // mark in-flight by key
        inFlightByKey[ent.key] = rid;
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;

    // optional local cache (not used to serve reads to ensure LSI unless validated via storage)
    var cache: map[int, int];

    // read coalescing: key -> set of waiting clients; presence implies an in-flight read via proxy
    var pendingReadWaiters: map[int, set[machine]];

    // write tracking: per-key queue of opIds and mapping opId -> client
    var pendingWriteQueueByKey: map[int, seq[int]];
    var pendingWriteClient: map[int, machine];

    var nextOpId: int;

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;

            cache = default(map[int, int]);
            pendingReadWaiters = default(map[int, set[machine]]);
            pendingWriteQueueByKey = default(map[int, seq[int]]);
            pendingWriteClient = default(map[int, machine]);

            nextOpId = 1;
            goto Ready;
        }
    }

    state Ready {
        // Client read: coalesce per-key and always fetch from storage via proxy to satisfy LSI
        on eClientRead do (r: (client: machine, key: int)) {
            var waiters: set[machine];
            var opId: int;

            if (r.key in pendingReadWaiters) {
                waiters = pendingReadWaiters[r.key];
                waiters += (r.client);
                pendingReadWaiters[r.key] = waiters;
                return;
            }

            waiters = default(set[machine]);
            waiters += (r.client);
            pendingReadWaiters[r.key] = waiters;

            // announce request issued toward proxy
            send proxy, eMonitorProxyRequestIssued, (key = r.key, podId = podId, isWrite = false);

            // send to proxy
            opId = nextOpId;
            nextOpId = nextOpId + 1;

            send proxy, eProxyReadReq, (from = this, key = r.key, opId = opId, podId = podId);
        }

        // Client write: send through proxy; track op ordering per key to match acks
        on eClientWrite do (w: (client: machine, key: int, value: int)) {
            var opId: int;
            var q: seq[int];

            // allocate op id and remember client
            opId = nextOpId;
            nextOpId = nextOpId + 1;
            pendingWriteClient[opId] = w.client;

            if (w.key in pendingWriteQueueByKey) {
                q = pendingWriteQueueByKey[w.key];
            } else {
                q = default(seq[int]);
            }
            q += (sizeof(q), opId);
            pendingWriteQueueByKey[w.key] = q;

            // announce request issued toward proxy
            send proxy, eMonitorProxyRequestIssued, (key = w.key, podId = podId, isWrite = true);

            // send to proxy
            send proxy, eProxyWriteReq, (from = this, key = w.key, value = w.value, opId = opId, podId = podId);
        }

        // Response to a proxied read; fan out to all coalesced waiters for the key
        on eReadResp do (resp: (key: int, value: int, fromCache: bool)) {
            var waiters: set[machine];
            var i: int;
            var client: machine;

            if (resp.key in pendingReadWaiters) {
                waiters = pendingReadWaiters[resp.key];

                // update local cache (not used for serving without validation)
                cache[resp.key] = resp.value;

                i = 0;
                while (i < sizeof(waiters)) {
                    client = waiters[i];
                    // deliver to client; fromCache=false since storage was touched
                    send client, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                    i = i + 1;
                }

                // clear waiters
                pendingReadWaiters -= (resp.key);
            }
        }

        // Response to a proxied write; match to the oldest pending op for this key and reply to its client
        on eWriteResp do (resp: (key: int, success: bool)) {
            var q: seq[int];
            var opId: int;
            var newQ: seq[int];
            var i: int;
            var client: machine;

            assert resp.key in pendingWriteQueueByKey, format("Write resp for key {0} but no pending ops!", resp.key);
            q = pendingWriteQueueByKey[resp.key];
            assert sizeof(q) > 0, format("Write resp for key {0} but empty queue!", resp.key);

            // take head opId
            opId = q[0];

            // remove head
            newQ = default(seq[int]);
            i = 1;
            while (i < sizeof(q)) {
                newQ += (sizeof(newQ), q[i]);
                i = i + 1;
            }
            if (sizeof(newQ) > 0) {
                pendingWriteQueueByKey[resp.key] = newQ;
            } else {
                pendingWriteQueueByKey -= (resp.key);
            }

            // reply to the client that issued this op
            assert opId in pendingWriteClient, "Missing client for completed write op!";
            client = pendingWriteClient[opId];
            pendingWriteClient -= (opId);

            send client, eWriteResp, (key = resp.key, success = resp.success);
        }
    }
}
